(function(){
'use strict';
window.__live_server_log__=[];
const STORAGE_KEY='IsThisFirstTime_Log_From_LiveServer++',
bodyRegex=/<body[^>]*>((.|[\n\r])*)<\/body>/i,
log=(...args)=>window.__live_server_log__.push(...args);

let dd,socket,isConnected=false;

// Lazy load diffDOM only when needed
function loadDiffDOM(){
if(!dd&&window.diffDOM){
dd=new diffDOM.DiffDOM({trimNodeTextValue:true});
}
return dd;
}

// Debounced DOM update to prevent excessive updates
const debouncedUpdate=(function(){
let timeout;
return function(fn,delay=16){
clearTimeout(timeout);
timeout=setTimeout(fn,delay);
};
})();

function updateDOM(newDOM){
const diffDom=loadDiffDOM();
if(!diffDom)return fullHTMLRerender(newDOM);

try{
const bodyMatch=newDOM.match(bodyRegex);
if(!bodyMatch)return;

const newBodyHTML=bodyMatch[1];
const tempDiv=document.createElement('div');
tempDiv.innerHTML=newBodyHTML;

const diff=diffDom.diff(document.body,tempDiv);
if(diff.length>50){
// Too many changes, do full reload
return fullHTMLRerender(newDOM);
}

debouncedUpdate(()=>{
diffDom.apply(document.body,diff);
});
}catch(e){
console.warn('Hot reload failed, falling back to full reload:',e);
fullHTMLRerender(newDOM);
}
}

function fullHTMLRerender(newDOM){
const bodyMatch=newDOM.match(bodyRegex);
if(bodyMatch){
debouncedUpdate(()=>{
document.body.innerHTML=bodyMatch[1];
});
}else{
fullBrowserReload();
}
}

function fullBrowserReload(){
window.location.reload();
}

// Optimized CSS refresh with batch processing
function refreshCSS(){
const sheets=[...document.querySelectorAll('link[rel="stylesheet"]')];
const head=document.head;
const timestamp=Date.now();

sheets.forEach((elem,i)=>{
const href=elem.getAttribute('href');
if(!href||href.startsWith('http'))return;

setTimeout(()=>{
const parent=elem.parentElement||head;
const newElem=elem.cloneNode();
const url=href.replace(/[?&]_cacheOverride=\d+/,'');
newElem.href=`${url}${url.includes('?')?'&':'?'}_cacheOverride=${timestamp}`;

parent.replaceChild(newElem,elem);
},i*10); // Stagger updates to prevent blocking
});
}

function getWatchList(){
return[window.location.pathname];
}

// Connection management with exponential backoff
function connectWebSocket(){
if(isConnected)return;

const protocol=window.location.protocol==='https:'?'wss://':'ws://';
const address=`${protocol}${window.location.host}/_ws_lspp`;

try{
socket=new WebSocket(address);

socket.onmessage=function(msg){
try{
const{action,data}=JSON.parse(msg.data);
switch(action){
case'refreshcss':refreshCSS();break;
case'reload':fullBrowserReload();break;
case'hot':updateDOM(data.dom);break;
case'partial-reload':fullHTMLRerender(data.dom);break;
}
}catch(e){
console.error('Failed to process message:',e);
}
};

socket.onopen=()=>{
isConnected=true;
log('WebSocket connected');
socket.send(JSON.stringify({watchList:getWatchList()}));
if(!sessionStorage.getItem(STORAGE_KEY)){
console.log('Live Server++: Connected!');
sessionStorage.setItem(STORAGE_KEY,'true');
}
};

socket.onclose=socket.onerror=()=>{
isConnected=false;
// Auto-reconnect after 2 seconds
setTimeout(connectWebSocket,2000);
};
}catch(e){
console.error('WebSocket connection failed:',e);
setTimeout(connectWebSocket,5000);
}
}

// Initialize on DOM ready with performance optimization
if(document.readyState==='loading'){
document.addEventListener('DOMContentLoaded',init);
}else{
init();
}

function init(){
if(!window.WebSocket){
console.error('WebSocket not supported');
return;
}

// Only load diffDOM if hot reloading is enabled
if(document.documentElement.hasAttribute('data-hot-reload')){
const script=document.createElement('script');
script.src='/_live-server_/inject/diffDOM.js';
script.onload=()=>connectWebSocket();
script.onerror=()=>{
console.warn('diffDOM failed to load, using basic reload');
connectWebSocket();
};
document.head.appendChild(script);
}else{
connectWebSocket();
}
}
})();